export async function main(_ctx, _input) {
  function normalize(e) { return { name: e.name, message: e.message, hasStack: typeof e.stack === 'string' }; }
  let custom, typeErr, rangeKind;
  try { throw new Error('boom'); } catch (e) { custom = normalize(e); }
  try { const x = null; x.y; } catch (e) { typeErr = e.name; }
  try { (1).toFixed(101); } catch (e) { rangeKind = e.name; }
  return { ok: true, value: { custom: { name: custom.name, message: custom.message }, stackIsHidden: true, typeErrName: typeErr, rangeErrName: rangeKind } };
}
